/// Apple Root Cert.
pub const APPLE_ROOT_CERT: &str = "";

/// First decode the raw attestation and key_id objects. Then validate.
pub fn validate_attestation(
    attestation_hex: &str,
    key_id_hex: &str,
    challenge: &str,
    app_id: &str,
    production: bool,
    leaf_cert_only: bool,
) -> Result<String, Error> {
    let attestation = utils::decode_attestation(attestation_hex.to_string()).unwrap();
    let key_id = utils::decode_base64_to_bytes(key_id_hex)?;

    attestation::validate_attestation(
        attestation,
        challenge.to_string(),
        key_id,
        app_id.to_string(),
        production,
        leaf_cert_only,
    )
}

/// Decode a raw assertion and client data object. Then validate.
pub fn validate_assertion(
    assertion_hex: &str,
    client_data_hex: &str,
    public_key_uncompressed_hex: &str,
    client_app_id: &str,
    prev_counter: u32,
) -> Result<bool, Error> {
    let assertion = utils::decode_assertion(assertion_hex.to_string()).unwrap();
    let client_data = utils::decode_base64_to_bytes(client_data_hex)?;

    assertion::validate_assertion(
        assertion,
        client_data,
        public_key_uncompressed_hex.to_string(),
        client_app_id.to_string(),
        prev_counter,
    )
}

#[cfg(test)]
mod tests {
    use base64ct::{Base64, Encoding};

    use crate::{
        certificate::public_key_uncompressed_hex, utils::decode_attestation, validate_assertion,
        validate_attestation,
    };

    const DEVICE_KEY_ID: &str = "3EUaLHJnzUZkLWaRgzv2JHGpsduSqmG1Colm/VQsJPc=";

    const APP_ID: &str = "NLS5R4YCGX.com.anonymous.zcam1poc";

    const ATTESTATION: &str = "";

    const ASSERTION: &str = "omlzaWduYXR1cmVYRjBEAiBeAesswnNnRVkufK9+gXqi2yrnKq/DeuLjEr+SAsKWrAIgaOWOxGv1+Ljmese+oVYgZhN2sV2IpHaK8zmqHZJei1JxYXV0aGVudGljYXRvckRhdGFYJQuHzQOLi5nuiKIkVTA0ikS1OWf+kj5Q5yGhnfEA7rhtQAAAAAE=";

    #[test]
    fn test_valid_attestation() {
        let result = validate_attestation(
            ATTESTATION,
            DEVICE_KEY_ID,
            "CHALLENGE",
            APP_ID,
            false,
            false,
        );

        assert!(result.is_ok())
    }

    #[test]
    fn test_valid_assertion() {
        let attestation = decode_attestation(ATTESTATION.to_string()).unwrap();
        let public_key_uncompressed_hex =
            public_key_uncompressed_hex(&attestation.att_stmt.x5c[0]).unwrap();

        let is_valid = validate_assertion(
            ASSERTION,
            &Base64::encode_string("HASH".as_bytes()),
            &public_key_uncompressed_hex,
            APP_ID,
            0,
        )
        .unwrap();

        assert!(is_valid)
    }
}
